"""CMD-V3-01 — Pydantic type round-trips for CommandBundle / BundleResult."""

from __future__ import annotations

import pytest
from pydantic import ValidationError

from bim_ai.cmd.types import AssumptionEntry, BundleResult, CommandBundle, ToleranceEntry


_VALID_ASSUMPTION = {
    "key": "site_width_m",
    "value": 15.0,
    "confidence": 0.9,
    "source": "brief",
}


class TestAssumptionEntry:
    def test_valid_round_trip(self):
        entry = AssumptionEntry.model_validate(_VALID_ASSUMPTION)
        assert entry.key == "site_width_m"
        assert entry.confidence == 0.9
        assert entry.contestable is True
        assert entry.evidence is None

    def test_confidence_bounds_zero(self):
        AssumptionEntry.model_validate({**_VALID_ASSUMPTION, "confidence": 0.0})

    def test_confidence_bounds_one(self):
        AssumptionEntry.model_validate({**_VALID_ASSUMPTION, "confidence": 1.0})

    def test_confidence_out_of_range_high(self):
        with pytest.raises(ValidationError):
            AssumptionEntry.model_validate({**_VALID_ASSUMPTION, "confidence": 1.01})

    def test_confidence_out_of_range_low(self):
        with pytest.raises(ValidationError):
            AssumptionEntry.model_validate({**_VALID_ASSUMPTION, "confidence": -0.01})

    def test_empty_key_rejected(self):
        with pytest.raises(ValidationError):
            AssumptionEntry.model_validate({**_VALID_ASSUMPTION, "key": ""})

    def test_missing_key_rejected(self):
        with pytest.raises(ValidationError):
            data = {k: v for k, v in _VALID_ASSUMPTION.items() if k != "key"}
            AssumptionEntry.model_validate(data)

    def test_optional_evidence_populated(self):
        entry = AssumptionEntry.model_validate({**_VALID_ASSUMPTION, "evidence": "page 3 of brief"})
        assert entry.evidence == "page 3 of brief"


class TestCommandBundle:
    def _make(self, **overrides):
        data = {
            "schemaVersion": "cmd-v3.0",
            "commands": [{"type": "createLevel", "id": "lvl", "name": "G", "elevationMm": 0}],
            "assumptions": [_VALID_ASSUMPTION],

def try_commit_bundle(
    doc: Document,
    cmds_raw: list[dict[str, Any]],
    *,
    source_provider: SourceDocProvider | None = None,
) -> tuple[bool, Document | None, list[Command], list[Violation], str]:
    try:
        cmds: list[Command] = [coerce_command(c) for c in cmds_raw]
    except Exception as exc:
        return False, None, [], [], str(exc)
    cand = clone_document(doc)
    # KRN-06: backfill the singleton on every commit so persisted state always
    # has it (matches `try_commit`'s behaviour for the single-command path).
    ensure_internal_origin(cand)
    try:
        for cmd in cmds:
            apply_inplace(cand, cmd, source_provider=source_provider)
    except (ValueError, KeyError) as exc:
        return False, None, cmds, [], str(exc)

    ensure_sun_settings(cand)
    violations = evaluate(cand.elements)

    # EDT-02 — reject bundles that break an error-severity locked constraint.
    # Runs after every command apply; the clone rollback is implicit because
    # we never return ``cand`` on failure.
    edt_violations = _evaluate_edt_constraint_violations(cand.elements)
    violations = violations + edt_violations

    blocking = [v for v in violations if v.blocking or v.severity == "error"]
    if blocking:
        return False, None, cmds, violations, "constraint_error"

    cand.revision = doc.revision + 1

    _assert_tkn_round_trip(cand)

    return True, cand, cmds, violations, "ok"

